import{_ as l}from"./plugin-vue_export-helper.21dcd24c.js";import{r as i,o as a,c as u,a as e,b as n,d as t,e as h}from"./app.7aa27cff.js";const d={},o=e("h1",{id:"\u7B2C\u4E8C\u7248\u5E8F",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#\u7B2C\u4E8C\u7248\u5E8F","aria-hidden":"true"},"#"),t(" \u7B2C\u4E8C\u7248\u5E8F")],-1),s=t("\u672C\u4E66\u662F"),c={href:"https://github.com/flutterchina",target:"_blank",rel:"noopener noreferrer"},F=t("Flutter\u4E2D\u56FD\u5F00\u6E90\u9879\u76EE"),p=t("\u53D1\u8D77\u4EBA\u675C\u6587\uFF08\u7F51\u540Dwendux\uFF09 \u521B\u4F5C\u7684\u4E00\u672C\u7CFB\u7EDF\u4ECB\u7ECDFlutter\u6280\u672F\u7684\u4E2D\u6587\u4E66\u7C4D\uFF0C\u65E8\u5728\u5E2E\u52A9\u5F00\u53D1\u8005\u5165\u95E8\uFF0C\u7CFB\u7EDF\u5730\u3001\u5FAA\u5E8F\u6E10\u8FDB\u7684\u4E86\u89E3Flutter\u3002"),_=h('<p>\u8F6C\u773C\u95F4\u4ECE\u672C\u4E66\u7B2C\u4E00\u7248\u7535\u5B50\u7248\u53D1\u5E03\u5230\u73B0\u5728\u5DF2\u7ECF\u63A5\u8FD1\u4E24\u5E74\u65F6\u95F4\uFF0C\u8FD9\u4E24\u5E74\u4E2D\uFF0C\u672C\u4E66\u5B9E\u4F53\u4E66\u51FA\u7248\u5E76\u6210\u4E3AFlutter\u6280\u672F\u7C7B\u7545\u9500\u4E66\u4E4B\u4E00\uFF0C\u672C\u4E66\u7535\u5B50\u7248\u5B98\u7F51UV \u8D85 60 \u4E07\uFF0C\u65E5\u8BBF\u95EE\u4EBA\u6570\u957F\u671F\u7A33\u5B9A\u57283500\u3002\u5F53\u7136\uFF0C\u672C\u4E66\u53D6\u5F97\u5982\u6B64\u6210\u7EE9\u6700\u4E3B\u8981\u7684\u4E00\u4E2A\u56E0\u7D20\u662F\u8FD9\u4E24\u5E74 Flutter \u6280\u672F\u70ED\u5EA6\u6301\u7EED\u63D0\u9AD8\uFF0C\u6574\u4E2A Flutter \u751F\u6001\u548C\u793E\u533A\u4E5F\u53D1\u751F\u4E86\u7FFB\u5929\u8986\u5730\u7684\u53D8\u5316\uFF0C\u4E3B\u8981\u4F53\u73B0\u5728\uFF1A</p><ul><li>Flutter \u7A33\u5B9A\u7248\u53D1\u5E03\u5230\u4E862.10\uFF0C\u73B0\u5728\u5DF2\u7ECF\u652F\u6301\u79FB\u52A8\u7AEF\u3001Web\u7AEF\u548CPC\u7AEF\uFF0C\u901A\u8FC7Flutter \u5F00\u53D1\u7684\u5E94\u7528\u7A0B\u5E8F\u80FD\u591F\u8F7B\u677E\u7684\u5728\u5404\u4E2A\u5E73\u53F0\u8FC1\u79FB\u5E76\u83B7\u5F97\u5F88\u597D\u7684\u6027\u80FD\u3002</li><li>Flutter \u5728 Github Star \u6570\u4E0A\u6392\u540D\u5DF2\u7ECF\u8FDB\u5165\u4E86\u524D20\uFF0C\u5728\u8DE8\u7AEF\u6846\u67B6\u4E2D\u5DF2\u7ECF\u6210\u4E3A\u7A33\u7A33\u7684\u7B2C\u4E00\u3002</li><li>\u5168\u7403\u5F88\u591A\u516C\u53F8\u90FD\u5DF2\u7ECF\u5728\u5546\u4E1A\u9879\u76EE\u4E2D\u4F7F\u7528 Flutter\uFF0C\u6BD4\u5982Google\u3001\u5FAE\u8F6F\u3001\u963F\u91CC\u3001\u5B57\u8282\u3001\u767E\u5EA6\u3001\u4EAC\u4E1C\u7B49\uFF0C\u5DF2\u7ECF\u6709\u5F88\u591A\u6210\u529F\u6848\u4F8B\u3002</li><li>Flutter \u7B2C\u4E09\u65B9\u5E93\u6570\u91CF\u6301\u7EED\u4FDD\u6301\u9AD8\u901F\u589E\u957F\uFF0C\u6709\u8D8A\u6765\u8D8A\u591A\u7684\u4EBA\u4E3AFlutter\u751F\u6001\u8D21\u732E\u4EE3\u7801\u3002Flutter \u76F8\u5173\u7684\u6559\u7A0B\u3001\u4E66\u7C4D\u6570\u91CF\u4E5F\u5728\u9AD8\u901F\u589E\u957F\u3002</li></ul><p>\u7EFC\u4E0A\uFF0C\u53EF\u4EE5\u770B\u89C1Flutter \u6280\u672F\u4ECE\u7B2C\u4E00\u4E2A\u6D4B\u8BD5\u7248\u53D1\u5E03\u5230\u73B0\u5728\u77ED\u77ED 3 \u5E74\u591A\u65F6\u95F4\u83B7\u5F97\u4E86\u5DE8\u5927\u7684\u6210\u529F\u3002\u800C\u4E4B\u6240\u4EE5\u80FD\u83B7\u5F97\u6210\u529F\u7684\u4E3B\u8981\u539F\u56E0\u662F\uFF1AFlutter \u65E2\u80FD\u4FDD\u6301\u5F88\u9AD8\u7684\u5F00\u53D1\u6548\u7387\u7684\u53C8\u80FD\u83B7\u5F97\u4E1D\u6ED1\u7684\u6027\u80FD\u3002\u6839\u636E\u8FD1\u51E0\u5E74\u5B9E\u8DF5\u7EDF\u8BA1\uFF0CFlutter \u76F8\u6BD4\u539F\u751F\u5F00\u53D1\uFF0C\u4EBA\u6548\u80FD\u63D0\u9AD8\u8FD1\u4E00\u500D\uFF0C\u800C\u6027\u80FD\u53EF\u4EE5\u63A5\u8FD1\u539F\u751F\u3002</p><p>\u6B63\u662F\u56E0\u4E3AFlutter \u6280\u672F\u53D1\u5C55\u592A\u5FEB\uFF0C\u672C\u4E66\u7B2C\u4E00\u7248\u4E2D\u7684\u90E8\u5206\u5185\u5BB9\u5DF2\u7ECF\u8FC7\u65F6\uFF0C\u5728\u8BFB\u8005\u4EEC\u7684\u50AC\u4FC3\u4E0B\uFF0C\u624D\u6709\u4E86\u7B2C\u4E8C\u7248\u7684\u66F4\u65B0\u3002\u76EE\u524D\u7B2C\u4E8C\u7248\u5904\u4E8E\u8349\u7A3F\u9636\u6BB5\uFF0C\u5C1A\u672A\u6B63\u5F0F\u5B8C\u6210\uFF0C\u5904\u4E8E\u9884\u89C8\u9636\u6BB5\uFF0C\u5927\u5BB6\u5982\u6709\u5185\u5BB9\u4E0A\u7684\u5EFA\u8BAE\u53EF\u4EE5\u76F4\u63A5\u5728 github \u4E0A\u63D0 issue\u3002</p><h2 id="\u7B2C\u4E8C\u7248\u53D8\u5316" tabindex="-1"><a class="header-anchor" href="#\u7B2C\u4E8C\u7248\u53D8\u5316" aria-hidden="true">#</a> \u7B2C\u4E8C\u7248\u53D8\u5316</h2><p>\u4E3B\u8981\u6709\u4EE5\u4E0B\u53D8\u5316\uFF1A</p><ul><li>\u57FA\u4E8E\u6700\u65B0\uFF082022.2\uFF09\u7684 Flutter/Dart \u7248\u672C\uFF08Flutter 2.10\uFF09\uFF0C\u5BF9\u4E8E\u4E66\u4E2D\u4F9D\u8D56\u7684\u7B2C\u4E09\u65B9\u5E93\u90FD\u4F1A\u5347\u7EA7\u5230\u6700\u65B0\u7248\u672C\u3002</li><li>\u6709 60% \u7684\u5185\u5BB9\u8FDB\u884C\u4E86\u4FEE\u6539\u548C\u91CD\u6784\uFF0C\u6DFB\u52A0\u4E86\u66F4\u591A\u7684\u793A\u4F8B\uFF0C\u5BF9\u90E8\u5206\u7AE0\u8282\u7684\u987A\u5E8F\u8FDB\u884C\u4E86\u8C03\u6574\uFF0C\u4F7F\u5B66\u4E60\u7684\u68AF\u5EA6\u66F4\u52A0\u5408\u7406\uFF0C\u4EE5\u671F\u80FD\u591F\u5FAA\u5E8F\u6E10\u8FDB\u7684\u5E2E\u52A9\u8BFB\u8005\u4E86\u89E3Flutter\u3002</li><li>\u8FDB\u9636\u7BC7\u4E2D\u5BF9Flutter\u4E2D\u76F8\u5BF9\u8F83\u6DF1\u4F46\u5F88\u91CD\u8981\u7684\u5185\u5BB9\u8FDB\u884C\u4E86\u6DF1\u5165\u4ECB\u7ECD\uFF0C\u6BD4\u5982\u53EFSliver\u5E03\u5C40\u534F\u8BAE\u3001\u6E32\u67D3\u76F8\u5173\u7684 Layer \u4EE5\u53CA\u901A\u8FC7\u5B9A\u4E49 RenderObject \u7684\u65B9\u5F0F\u6765\u5B9A\u4E49\u7EC4\u4EF6\u3002</li><li>Flutter \u6838\u5FC3\u539F\u7406\u4E00\u7AE0\u8FDB\u884C\u4E86\u91CD\u5199\uFF0C\u4E0D\u518D\u53EA\u662F\u505C\u7559\u5728\u6587\u5B57\u4ECB\u7ECD\uFF0C\u540C\u65F6\u6DFB\u52A0\u4E86\u5F88\u591A\u5B9E\u4F8B\u6765\u8F85\u52A9\u7406\u89E3Flutter \u7684\u5E03\u5C40\u3001\u7ED8\u5236\u7B49\u539F\u7406\u3002</li><li>\u672C\u4E66\u5185\u5BB9\u66F4\u805A\u7126\u4E8Eflutter\u6280\u672F\u672C\u8EAB\uFF0C\u5220\u9664\u4E86\u4E00\u4E9B\u548C\u5177\u4F53\u5E73\u53F0\u76F8\u5173\u7684\u5185\u5BB9\uFF0C\u6BD4\u5982Android\u548CiOS\u7684\u63D2\u4EF6\u5F00\u53D1\uFF0C\u4EE5\u53CA\u5982\u4F55\u8FDB\u884C\u539F\u751F+flutter\u6DF7\u5408\u5F00\u53D1\u7B49\uFF0C\u8FD9\u4E9B\u5185\u5BB9\u8BFB\u8005\u53EF\u4EE5\u53BBflutter\u5B98\u7F51\u67E5\u627E\u76F8\u5E94\u6559\u7A0B\u3002</li><li>\u7535\u5B50\u7248\u6DFB\u52A0\u4E86\u4E00\u4E9B\u52A8\u56FE\u3002</li><li>\u4FEE\u6539\u4E86\u7B2C\u4E00\u7248\u4E2D\u7684\u4E00\u4E9B\u9519\u8BEF\u3002</li></ul><h2 id="\u672C\u4E66\u7EC4\u7EC7\u7ED3\u6784" tabindex="-1"><a class="header-anchor" href="#\u672C\u4E66\u7EC4\u7EC7\u7ED3\u6784" aria-hidden="true">#</a> \u672C\u4E66\u7EC4\u7EC7\u7ED3\u6784</h2><p>\u672C\u4E66\u91C7\u7528\u7531\u6D45\u5165\u6DF1\u7684\u65B9\u5F0F\u4ECB\u7ECDFlutter\u6280\u672F\u539F\u7406\uFF0C\u5206\u4E3A\u4E09\u7BC7\uFF0C\u603B\u8BA115\u7AE0\uFF0C\u5404\u7BC7\u7684\u4E3B\u8981\u5185\u5BB9\u5982\u4E0B\u3002</p><ul><li>\u7B2C\u4E00\u7BC7\uFF0C\u5165\u95E8\u7BC7\uFF08\u7B2C1\u7AE0~\u7B2C5\u7AE0\uFF09\uFF0C\u5305\u62ECFlutter\u6280\u672F\u7684\u51FA\u73B0\u80CC\u666F\u548C\u7B80\u4ECB\u3001Flutter\u7684\u5404\u79CD\u7C7B\u578B\u7684Widget\u4EE5\u53CA\u5982\u4F55\u6784\u5EFAUI\u3002\u901A\u8FC7\u5B66\u4E60\u672C\u7AE0\uFF0C\u8BFB\u8005\u53EF\u4EE5\u638C\u63E1\u5982\u4F55\u4F7F\u7528Flutter\u6765\u6784\u5EFAUI\u754C\u9762\u3002</li><li>\u7B2C\u4E8C\u7BC7\uFF0C\u8FDB\u9636\u7BC7\uFF08\u7B2C6\u7AE0~\u7B2C14\u7AE0\uFF09\uFF0C\u5305\u62EC\u53EF\u6EDA\u52A8\u7EC4\u4EF6\u3001\u4E8B\u4EF6\u673A\u5236\u3001\u52A8\u753B\u3001\u81EA\u5B9A\u4E49\u7EC4\u4EF6\u3001\u6587\u4EF6\u548C\u7F51\u7EDC\u3001\u56FD\u9645\u5316\u4EE5\u53CAFlutter\u6838\u5FC3\u539F\u7406\u7B49\u3002\u901A\u8FC7\u672C\u7AE0\u5185\u5BB9\uFF0C\u8BFB\u8005\u53EF\u4EE5\u5BF9Flutter\u6574\u4F53\u6784\u5EFA\u53CA\u539F\u7406\u6709\u4E00\u4E2A\u6DF1\u5165\u7684\u8BA4\u8BC6\u3002</li><li>\u7B2C\u4E09\u7BC7\uFF0C\u5B9E\u4F8B\u7BC7\uFF08\u7B2C15\u7AE0\uFF09\uFF0C\u672C\u7AE0\u4E3B\u8981\u901A\u8FC7\u4E00\u4E2A\u7B80\u7248\u7684Github APP\u6765\u5C06\u524D\u9762\u4ECB\u7ECD\u7684\u5185\u5BB9\u4E32\u8D77\u6765\uFF0C\u8BA9\u5F00\u53D1\u8005\u5BF9\u4E00\u4E2A\u5B8C\u6574\u7684Flutter APP\u5F00\u53D1\u6D41\u6709\u4E2A\u4E86\u89E3\u3002</li></ul><p>\u7531\u4E8EFlutter\u7684\u5F88\u591A\u77E5\u8BC6\u70B9\u662F\u76F8\u4E92\u4EA4\u7EC7\u7684\uFF0C\u5F88\u96BE\u5C06\u5B83\u4EEC\u5F7B\u5E95\u5212\u5206\u5F00\uFF0C\u6240\u4EE5\u672C\u4E66\u4E2D\u4E5F\u96BE\u514D\u4F1A\u51FA\u73B0\u4E00\u4E9B\u5728\u524D\u9762\u7AE0\u8282\u4F1A\u4F7F\u7528\u5728\u540E\u9762\u7AE0\u8282\u7684\u573A\u666F\uFF0C\u6BD4\u5982\u6211\u4EEC\u5728\u5165\u95E8\u7BC7\u4ECB\u7ECD\u8FDB\u5EA6\u6307\u793A\u5668\u65F6\u4F1A\u7528\u5230\u5728\u8FDB\u9636\u7BC7\u4E2D\u624D\u4ECB\u7ECD\u7684\u52A8\u753B\u76F8\u5173\u77E5\u8BC6\u3002\u672C\u4E66\u4E2D\u5BF9\u4E8E\u8FD9\u79CD\u60C5\u51B5\u4F1A\u5728\u76F8\u5E94\u7684\u7AE0\u8282\u8FDB\u884C\u8BF4\u660E\u3002\u8BFB\u8005\u53EF\u4EE5\u76F4\u63A5\u8DF3\u5230\u540E\u9762\u76F8\u5E94\u77E5\u8BC6\u70B9\u7AE0\u8282\u9605\u8BFB\u540E\u518D\u8FD4\u56DE\uFF0C\u4E5F\u53EF\u4EE5\u5148\u6709\u4E2A\u5370\u8C61\uFF0C\u5F85\u5B66\u4E60\u5230\u540E\u9762\u76F8\u5173\u7AE0\u8282\u540E\u518D\u56DE\u5934\u6765\u770B\u3002</p><h2 id="\u672C\u4E66\u7279\u8272" tabindex="-1"><a class="header-anchor" href="#\u672C\u4E66\u7279\u8272" aria-hidden="true">#</a> \u672C\u4E66\u7279\u8272</h2><p>\u7B14\u8005\u5728\u5927\u5B66\u65F6\u8BFB\u8FC7\u5019\u6377\uFF08\u771F\u540D\u4FAF\u4FCA\u6770\uFF09\u5199\u7684\u4E00\u4E9B C++ \u76F8\u5173\u4E66\u7C4D\uFF0C\u5728\u4ED6\u7684\u300A\u6DF1\u5165\u6D45\u51FAMFC\u300B\u4E00\u4E66\u4E2D\uFF0C\u6709\u4E00\u53E5\u8BDD\u6211\u5370\u8C61\u975E\u5E38\u6DF1 \u201C\u552F\u6709\u6DF1\u5165\uFF0C\u65B9\u80FD\u6D45\u51FA\u201D\u3002\u6211\u975E\u5E38\u8BA4\u540C\u8FD9\u53E5\u8BDD\uFF0C\u5BF9\u4E8E\u4E00\u95E8\u6280\u672F\uFF0C\u53EA\u6709\u4E86\u89E3\u7684\u6DF1\u5165\uFF0C\u624D\u80FD\u7528\u6700\u6D45\u663E\u3001\u901A\u4FD7\u7684\u8BDD\u8BED\u63CF\u8FF0\u51FA\u3002\u6211\u5728\u5199\u4F5C\u672C\u4E66\u65F6\uFF0C\u6DF1\u5165\u6D45\u51FA\u5C31\u662F\u4E00\u4E2A\u4E3B\u8981\u76EE\u6807\u3002\u6240\u4EE5\uFF0C\u672C\u4E66\u7684\u76EE\u6807\u4E0D\u4EC5\u662F\u60F3\u544A\u8BC9\u8BFB\u8005\u5982\u4F55\u4F7F\u7528Flutter\uFF0C\u800C\u4E14\u4E5F\u975E\u5E38\u5173\u6CE8\u5404\u4E2A\u77E5\u8BC6\u70B9\u7684\u5E95\u5C42\u5B9E\u73B0\u4EE5\u53CA\u8BBE\u8BA1\u601D\u60F3\u3002\u4ECE\u672C\u4E66\u7AE0\u8282\u5212\u5206\u4E0A\u6765\u770B\uFF0C\u5165\u95E8\u7BC7\u4E3A\u201C\u6D45\u51FA\u201D\uFF0C\u8FDB\u9636\u7BC7\u5219\u662F\u201C\u6DF1\u5165\u201D\u3002\u53E6\u5916\u7531\u4E8EPC\u5BA2\u6237\u7AEF\u5F00\u53D1\u3001\u79FB\u52A8\u5F00\u53D1\u3001Web\u5F00\u53D1\u8FD9\u4E9B\u7ECF\u9A8C\u6211\u90FD\u6709\uFF0C\u800CFlutter\u672C\u8D28\u4E0A\u662F\u4E00\u4E2AUI\u7CFB\u7EDF\uFF0C\u800CUI\u7CFB\u7EDF\u7684\u8BBE\u8BA1\u548C\u5B9E\u73B0\u5728\u201D\u5927\u524D\u7AEF\u201C\u4E0B\u6709\u5F88\u591A\u76F8\u901A\u4E4B\u5904\uFF0C\u6240\u4EE5\u5728\u672C\u4E66\u4E2D\u7684\u4E00\u4E9B\u77E5\u8BC6\u70B9\u6211\u4E5F\u4F1A\u5BF9\u6BD4\u4E00\u4E9B\u5176\u4ED6UI\u7CFB\u7EDF\uFF08\u4E3B\u8981\u662F Android \u6216 Web\uFF09\u76F8\u5E94\u7684\u5B9E\u73B0\uFF0C\u4FBF\u4E8E\u6709\u76F8\u5173\u5F00\u53D1\u7ECF\u9A8C\u7684\u8BFB\u8005\u5BF9\u6BD4\u7406\u89E3\u3002</p><h2 id="\u672C\u4E66\u8BFB\u8005\u5BF9\u8C61" tabindex="-1"><a class="header-anchor" href="#\u672C\u4E66\u8BFB\u8005\u5BF9\u8C61" aria-hidden="true">#</a> \u672C\u4E66\u8BFB\u8005\u5BF9\u8C61</h2><ul><li>\u8BFB\u8005\u81F3\u5C11\u719F\u6089\u4E00\u79CD\u7F16\u7A0B\u8BED\u8A00\u3002</li><li>\u8BFB\u8005\u6700\u597D\u63A5\u89E6\u8FC7PC\u5BA2\u6237\u7AEF\u3001\u79FB\u52A8\u5F00\u53D1\u6216Web\u524D\u7AEF\u5F00\u53D1\u4E2D\u7684\u4E00\u79CD\u3002</li><li>\u672C\u4E66\u4E0D\u9002\u5408\u505A\u4E3A\u7F16\u7A0B\u7684\u5165\u95E8\u8BFB\u7269\u3002</li></ul><h2 id="\u5173\u4E8E\u968F\u4E66\u6E90\u7801" tabindex="-1"><a class="header-anchor" href="#\u5173\u4E8E\u968F\u4E66\u6E90\u7801" aria-hidden="true">#</a> \u5173\u4E8E\u968F\u4E66\u6E90\u7801</h2><p>\u7531\u4E8E\u5F53\u524D\u5904\u4E8E\u8349\u7A3F\u9636\u6BB5\uFF0C\u5F85\u672C\u4E66\u6B63\u5F0F\u53D1\u5E03\u540E\u4F1A\u4E0A\u4F20\u968F\u4E66\u6E90\u7801\u3002</p><h2 id="\u6743\u76CA" tabindex="-1"><a class="header-anchor" href="#\u6743\u76CA" aria-hidden="true">#</a> \u6743\u76CA</h2><p>\u6700\u540E\uFF0C\u77E5\u8BC6\u662F\u5E94\u8BE5\u4ED8\u8D39\u7684\uFF0C\u521B\u4F5C\u4E0D\u6613\uFF0C\u5F00\u6E90\u4E0D\u7B49\u4E8E\u514D\u8D39\uFF0C\u5982\u679C\u60A8\u662F\u672C\u4E66\u8BFB\u8005\u5E76\u624B\u5934\u5BBD\u88D5\uFF0C\u53EF\u4EE5\u70B9\u51FB\u4E0B\u9762\u6253\u8D4F\u6309\u94AE\u6253\u8D4F\uFF1B\u5F53\u7136\uFF0C\u5982\u679C\u60A8\u56CA\u4E2D\u7F9E\u6DA9\uFF0C\u60A8\u4E5F\u53EF\u4EE5\u9605\u8BFB\u672C\u4E66\uFF0C\u4F46\u6211\u5BF9\u60A8\u6709\u4E2A\u5C0F\u5C0F\u7684\u8981\u6C42\uFF0C\u5E0C\u671B\u60A8\u5728\u9605\u8BFB\u7684\u8FC7\u7A0B\u4E2D\u80FD\u79EF\u6781\u53C2\u4E0E\u5230\u672C\u4E66\u7684\u7EA0\u9519\u4EE5\u53CA\u672A\u5B8C\u6210\u5185\u5BB9\u7684\u521B\u4F5C\u4E0A\u6765\uFF0C\u4E5F\u7B97\u662F\u6709\u6240\u4ED8\u51FA\u3002</p><p>\u8FD1\u6765\u5728\u7F51\u4E0A\u53D1\u73B0\u5F88\u591A<strong>\u539F\u5C01\u4E0D\u52A8\u590D\u5236\u672C\u4E66</strong>\u7684\u955C\u50CF\u7F51\u7AD9\u548C\u5927\u91CF\u590D\u5236\u6216<strong>\u5F15\u7528\u4E86\u672C\u4E66\u4F46\u672A\u6CE8\u660E\u51FA\u5904</strong>\u7684\u535A\u5BA2\u3001\u6587\u7AE0\u751A\u81F3\u4E66\u7C4D\uFF1B\u5BF9\u6B64\uFF0C\u7B14\u8005\u5728\u6B64\u58F0\u660E\uFF0C\u672C\u4E66\u8457\u4F5C\u6743\u5F52wendux\u6240\u6709\uFF0C\u4EFB\u4F55\u7EC4\u7EC7\u6216\u4E2A\u4EBA\u5728\u672A\u7ECF\u6388\u6743\u7684\u60C5\u51B5\u4E0B\u590D\u5236\u3001\u62F7\u8D1D\u3001\u6284\u88AD\u672C\u4E66\u7528\u4E8E\u5546\u4E1A\u76EE\u7684\uFF0C\u7B14\u8005\u4FDD\u7559\u8FFD\u7A76\u5176\u6CD5\u5F8B\u8D23\u4EFB\u7684\u6743\u5229\u3002\u5982\u679C\u662F\u975E\u5546\u4E1A\u76EE\u7684\u7684\u8F6C\u8F7D\u548C\u5F15\u7528\uFF0C\u8BF7\u6CE8\u660E\u51FA\u5904\u5E76\u9644\u4E0A\u672C\u4E66\u7F51\u5740\u3002</p><h3 id="\u52D8\u8BEF" tabindex="-1"><a class="header-anchor" href="#\u52D8\u8BEF" aria-hidden="true">#</a> \u52D8\u8BEF</h3><p>\u7531\u4E8EFlutter SDK\u5728\u4E0D\u65AD\u66F4\u65B0\uFF0C\u672C\u4E66\u4E2D\u7684\u90E8\u5206\u5185\u5BB9\uFF08\u5982\u7C7B\u7684\u7EE7\u627F\u5173\u7CFB\u3001\u53C2\u6570\u7B49\uFF09\u53EF\u80FD\u4F1A\u548C\u65B0\u7248\u672C\u7684Flutter\u4E0D\u4E00\u81F4\uFF0C\u8BFB\u8005\u4EE5\u6700\u65B0\u7684Flutter SDK\u4E3A\u51C6\u3002\u53E6\u5916\uFF0C\u7531\u4E8E\u65F6\u95F4\u4ED3\u4FC3\uFF0C\u4E66\u4E2D\u96BE\u514D\u6709\u9519\u8BEF\u4E4B\u5904\uFF0C\u5982\u679C\u53D1\u73B0\u9519\u8BEF\uFF0C\u53EF\u4EE5\u5728\u672C\u4E66Github\u9879\u76EEissue\u5217\u8868\u4E2D\u53BB\u53CD\u9988\uFF0C\u5730\u5740\u662Fhttps://github.com/flutterchina/flutter-in-action-2nd/issues \u3002\u53E6\u5916\u4F60\u4E5F\u53EF\u4EE5\u5173\u6CE8\u672C\u4E66\u7535\u5B50\u7248\u5B98\u7F51\uFF08https://book.flutterchina.club\uFF09\uFF0C\u7535\u5B50\u7248\u4F1A\u5B9A\u671F\u4FEE\u6B63\u9519\u8BEF\u53CA\u66F4\u65B0\u5185\u5BB9\u3002</p><h3 id="\u81F4\u8C22" tabindex="-1"><a class="header-anchor" href="#\u81F4\u8C22" aria-hidden="true">#</a> \u81F4\u8C22</h3><p>\u611F\u8C22\u4E00\u76F4\u4EE5\u6765\u652F\u6301Flutter\u4E2D\u6587\u7F51\u3001Flutter\u5F00\u6E90\u9879\u76EE\u7684\u4EBA\u4EE5\u53CA\u6240\u6709\u5BF9\u672C\u4E66\u63D0\u8FC7PR\u7684\u540C\u5B66\uFF1B\u611F\u8C22\u8BF7\u4F5C\u8005\u559D\u8FC7\u5496\u5561\u7684\u540C\u5B66\uFF1B\u611F\u8C22\u7B2C\u4E00\u7248\u7684\u8BFB\u8005\uFF0C\u6B63\u662F\u56E0\u4E3A\u6709\u4F60\u4EEC\u5929\u5929\u7763\u4FC3\u6211\u66F4\u65B0\u6211\u624D\u6709\u52A8\u529B\uFF1B\u6700\u540E\u611F\u8C22\u6240\u6709\u652F\u6301\u6211\u7684\u4EBA\u3002</p>',24);function f(b,x){const r=i("ExternalLinkIcon");return a(),u("div",null,[o,e("blockquote",null,[e("p",null,[s,e("a",c,[F,n(r)]),p])]),_])}var P=l(d,[["render",f],["__file","index.html.vue"]]);export{P as default};
